import"./ticker-BxUDbM2L.js";import{i as a}from"./country-page-CK6BdUjw.js";import"./utils-Owvk3OYq.js";import"./breadcrumbs-CxxVGuAV.js";a({countryCode:"IN",currency:"INR",flag:"🇮🇳",nameEn:"India",nameAr:"الهند",fixedPeg:!1,decimals:2,timezone:"Asia/Kolkata",relatedCountries:[{file:"uae.html",nameEn:"UAE",nameAr:"الإمارات",flag:"🇦🇪"},{file:"saudi-arabia.html",nameEn:"Saudi Arabia",nameAr:"السعودية",flag:"🇸🇦"},{file:"kuwait.html",nameEn:"Kuwait",nameAr:"الكويت",flag:"🇰🇼"},{file:"qatar.html",nameEn:"Qatar",nameAr:"قطر",flag:"🇶🇦"},{file:"egypt.html",nameEn:"Egypt",nameAr:"مصر",flag:"🇪🇬"},{file:"jordan.html",nameEn:"Jordan",nameAr:"الأردن",flag:"🇯🇴"}],faqEn:[{q:"What is today's gold price in India?",a:"The gold price in India is calculated by converting the global XAU/USD spot rate to Indian Rupees (INR) at the current exchange rate. India is the world's second-largest consumer of gold, with demand driven by jewellery, investment, and cultural traditions. Prices are updated every 90 seconds."},{q:"What karats are popular in India?",a:"22K is the most popular karat for jewellery in India, accounting for the majority of retail gold purchases. 24K gold is favoured for investment instruments such as Gold ETFs, Sovereign Gold Bonds, and bullion bars. 18K is commonly used for diamond and gemstone jewellery settings where a harder alloy is needed."},{q:"What taxes apply to gold in India?",a:"Gold in India is subject to a 3% Goods and Services Tax (GST) on the value of gold, plus an additional 5% GST on making charges for jewellery. Import duty on gold bullion is 10–15% depending on the form. These taxes are reflected in retail prices but are not included in the spot rate estimates shown on this page."},{q:"What is Hallmarking in India?",a:"BIS Hallmarking is mandatory for gold jewellery sold in India under the BIS (Bureau of Indian Standards) Act 2016. A hallmarked piece carries the BIS logo, the karat purity mark (e.g., 916 for 22K), and the assay centre identification mark. Always look for the hallmark when buying gold jewellery in India to ensure you receive the purity you are paying for."},{q:"Why is India's gold demand so high?",a:"Gold holds deep cultural, religious, and economic significance in India. It is central to weddings as bridal jewellery and dowry, is gifted during festivals such as Dhanteras and Akshaya Tritiya, and is widely regarded as a reliable form of savings and wealth preservation. These traditions, combined with a large population, make India one of the world's largest gold markets year after year."}],faqAr:[{q:"ما هو سعر الذهب اليوم في الهند؟",a:"يُحسب سعر الذهب في الهند عن طريق تحويل سعر XAU/USD الفوري العالمي إلى الروبية الهندية (INR) بسعر الصرف الحالي. تُعدّ الهند ثاني أكبر مستهلك للذهب في العالم، إذ يتأثر الطلب بالمجوهرات والاستثمار والتقاليد الثقافية. يتم تحديث الأسعار كل 90 ثانية."},{q:"ما هي العيارات الأكثر شيوعاً في الهند؟",a:"يُعدّ عيار 22 الأكثر شيوعاً للمجوهرات في الهند ويمثل الجزء الأكبر من مشتريات الذهب بالتجزئة. يُفضَّل عيار 24 للأدوات الاستثمارية كصناديق الذهب المتداولة (ETF) وسندات الذهب السيادية والسبائك. أما عيار 18 فيُستخدم على نطاق واسع في أطر مجوهرات الألماس والأحجار الكريمة التي تحتاج إلى سبيكة أكثر صلابة."},{q:"ما هي الضرائب المطبّقة على الذهب في الهند؟",a:"يخضع الذهب في الهند لضريبة السلع والخدمات (GST) بنسبة 3% على قيمة الذهب، بالإضافة إلى 5% GST على أجور الصنعة للمجوهرات. تتراوح رسوم الاستيراد على سبائك الذهب بين 10% و15% بحسب الشكل. تنعكس هذه الضرائب في أسعار التجزئة لكنها غير مشمولة في تقديرات السعر الفوري المعروضة في هذه الصفحة."},{q:"ما هو الطابع المعياري (Hallmarking) في الهند؟",a:"أصبح الطابع المعياري BIS إلزامياً لمجوهرات الذهب المباعة في الهند بموجب قانون مكتب المعايير الهندية (BIS) لعام 2016. تحمل القطعة المختومة شعار BIS وعلامة عيار النقاء (مثل 916 لعيار 22) وعلامة مركز الفحص المعتمد. احرص دائماً على البحث عن الطابع المعياري عند شراء مجوهرات الذهب في الهند للتأكد من حصولك على النقاء الذي تدفع ثمنه."},{q:"لماذا يرتفع الطلب على الذهب في الهند إلى هذا الحد؟",a:'يحتل الذهب مكانةً ثقافيةً ودينيةً واقتصاديةً عميقة في الهند. فهو محور حفلات الزفاف بوصفه مجوهرات العرائس والمهر، ويُهدى خلال الأعياد كـ"دهانتيراس" و"أكشايا ترتيا"، ويُعدّ على نطاق واسع شكلاً موثوقاً من أشكال الادخار وحفظ الثروة. هذه التقاليد، مقترنةً بتعداد سكاني ضخم، تجعل الهند في طليعة أكبر أسواق الذهب في العالم عاماً بعد عام.'}]});
